// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// GoogleでログインまたはID連携
	// (POST /auth/google)
	LoginWithGoogle(ctx context.Context, request LoginWithGoogleRequestObject) (LoginWithGoogleResponseObject, error)
	// メールアドレスとパスワードでログイン
	// (POST /auth/login)
	LoginWithEmail(ctx context.Context, request LoginWithEmailRequestObject) (LoginWithEmailResponseObject, error)
	// ログアウト
	// (POST /auth/logout)
	Logout(ctx context.Context, request LogoutRequestObject) (LogoutResponseObject, error)
	// OTPを検証してトークンを発行
	// (POST /auth/otp/verify)
	VerifyOtp(ctx context.Context, request VerifyOtpRequestObject) (VerifyOtpResponseObject, error)
	// アクセストークンを更新
	// (POST /auth/refresh)
	RefreshToken(ctx context.Context, request RefreshTokenRequestObject) (RefreshTokenResponseObject, error)
	// メールアドレスで新規登録
	// (POST /auth/register)
	RegisterWithEmail(ctx context.Context, request RegisterWithEmailRequestObject) (RegisterWithEmailResponseObject, error)
	// 画像をアップロードする
	// (POST /images)
	UploadImage(ctx context.Context, request UploadImageRequestObject) (UploadImageResponseObject, error)
	// 気になる一覧を取得する
	// (GET /interests)
	ListInterests(ctx context.Context, request ListInterestsRequestObject) (ListInterestsResponseObject, error)
	// 自分のプロフィールを取得する
	// (GET /profiles/me)
	GetMyProfile(ctx context.Context, request GetMyProfileRequestObject) (GetMyProfileResponseObject, error)
	// 自分のプロフィールを更新する
	// (PATCH /profiles/me)
	UpdateMyProfile(ctx context.Context, request UpdateMyProfileRequestObject) (UpdateMyProfileResponseObject, error)
	// プロフィールを初回作成する
	// (POST /profiles/me)
	CreateMyProfile(ctx context.Context, request CreateMyProfileRequestObject) (CreateMyProfileResponseObject, error)
	// 事柄一覧を検索する
	// (GET /things)
	ListThings(ctx context.Context, request ListThingsRequestObject) (ListThingsResponseObject, error)
	// 新しい事柄を作成する
	// (POST /things)
	CreateThing(ctx context.Context, request CreateThingRequestObject) (CreateThingResponseObject, error)
	// ユーザー一覧を取得する
	// (GET /users)
	ListUsers(ctx context.Context, request ListUsersRequestObject) (ListUsersResponseObject, error)
	// 新着ユーザー一覧を取得する
	// (GET /users/new)
	ListNewUsers(ctx context.Context, request ListNewUsersRequestObject) (ListNewUsersResponseObject, error)
	// 今日のピックアップユーザー一覧を取得する
	// (GET /users/pickup)
	ListPickupUsers(ctx context.Context, request ListPickupUsersRequestObject) (ListPickupUsersResponseObject, error)
	// おすすめユーザー一覧を取得する
	// (GET /users/recommend)
	ListRecommendUsers(ctx context.Context, request ListRecommendUsersRequestObject) (ListRecommendUsersResponseObject, error)
	// ユーザー詳細を取得する
	// (GET /users/{userId})
	GetUser(ctx context.Context, request GetUserRequestObject) (GetUserResponseObject, error)
	// 気になるを送る
	// (POST /users/{userId}/interests)
	SendInterest(ctx context.Context, request SendInterestRequestObject) (SendInterestResponseObject, error)
}

